const fs = require('fs');

const token = process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const loc = 'TW8JsPW5NMnA3tfK2XLn';

if (!token) {
  console.error('missing token');
  process.exit(1);
}

(async () => {
  const url = `https://services.leadconnectorhq.com/workflows/?locationId=${loc}`;
  const res = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Version: '2021-07-28',
      Accept: 'application/json'
    }
  });

  const raw = await res.text();
  let json;
  try {
    json = JSON.parse(raw);
  } catch {
    json = { raw };
  }

  if (res.status !== 200) {
    console.error('status', res.status, json);
    process.exit(2);
  }

  const workflows = json.workflows || json.data || [];
  const out = {
    timestamp: new Date().toISOString(),
    count: workflows.length,
    draft: workflows.filter(w => String(w.status || '').toLowerCase() === 'draft').length,
    published: workflows.filter(w => String(w.status || '').toLowerCase() === 'published').length,
    workflows: workflows.map(w => ({
      id: w.id,
      name: w.name,
      status: w.status,
      published: w.published,
      updatedAt: w.updatedAt || w.dateUpdated || null
    }))
  };

  fs.writeFileSync('reports/2026-03-21-tjb-workflow-inventory.json', JSON.stringify(out, null, 2));

  const normalize = (name) => String(name || '').trim().toLowerCase();
  const byName = {};
  for (const wf of out.workflows) {
    const key = normalize(wf.name);
    if (!key) continue;
    byName[key] = byName[key] || [];
    byName[key].push(wf);
  }

  const duplicates = Object.entries(byName)
    .filter(([, arr]) => arr.length > 1)
    .map(([name, arr]) => ({
      name,
      count: arr.length,
      ids: arr.map(a => a.id),
      statuses: arr.map(a => a.status)
    }));

  fs.writeFileSync('reports/2026-03-21-tjb-workflow-duplicates.json', JSON.stringify({
    timestamp: new Date().toISOString(),
    duplicates
  }, null, 2));

  console.log(JSON.stringify({
    status: res.status,
    count: out.count,
    draft: out.draft,
    published: out.published,
    duplicateSets: duplicates.length
  }, null, 2));
})();

